import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { toast } from 'react-toastify';
import { useAuth } from '../context/AuthContext';

const ScoreBadge = ({ label, score }) => {
  const color = score >= 70 ? '#10b981' : score >= 40 ? '#f59e0b' : '#ef4444';
  return (
    <div className="flex items-center gap-2">
      <span className="text-gray-400 text-xs">{label}</span>
      <div style={{ background: '#0a0d1a', width: 120, height: 6, borderRadius: 3 }}>
        <div style={{ background: color, width: `${score}%`, height: '100%', borderRadius: 3, transition: 'width 1s' }} />
      </div>
      <span style={{ color }} className="text-xs font-bold">{score}</span>
    </div>
  );
};

const statusColors = { pending: '#f59e0b', approved: '#10b981', rejected: '#ef4444' };

export default function InnovatorDashboard() {
  const { user } = useAuth();
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [deletingId, setDeletingId] = useState(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState(null);

  useEffect(() => {
    axios.get('/api/projects/my/projects')
      .then(r => setProjects(r.data))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const handleDelete = async (id) => {
    setDeletingId(id);
    try {
      await axios.delete(`/api/projects/${id}`);
      setProjects(prev => prev.filter(p => p._id !== id));
      setConfirmDeleteId(null);
      toast.success('Project deleted successfully.');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to delete project.');
    } finally {
      setDeletingId(null);
    }
  };

  return (
    <div style={{ background: '#0a0d1a', minHeight: '100vh' }} className="px-6 py-10">
      <div className="max-w-5xl mx-auto">
        <div className="flex items-center justify-between mb-10">
          <div>
            <h1 style={{ fontFamily: 'Syne, sans-serif' }} className="text-3xl font-bold">
              My Projects
            </h1>
            <p className="text-gray-400 mt-1">Welcome back, {user.name}</p>
          </div>
          <Link to="/innovator/submit"
            style={{ background: '#00d4aa', color: '#0a0d1a' }}
            className="px-6 py-2.5 rounded-xl font-bold text-sm hover:opacity-90 transition-all">
            + Submit Project
          </Link>
        </div>

        {loading ? (
          <div className="text-center text-gray-500 py-20">Loading your projects...</div>
        ) : projects.length === 0 ? (
          <div style={{ border: '1px dashed #374151' }} className="rounded-2xl p-16 text-center">
            <div className="text-4xl mb-4">🚀</div>
            <h2 className="text-xl font-semibold mb-2">No projects yet</h2>
            <p className="text-gray-400 mb-6 text-sm">Submit your first project and let AI evaluate it</p>
            <Link to="/innovator/submit"
              style={{ background: '#00d4aa', color: '#0a0d1a' }}
              className="px-6 py-2.5 rounded-xl font-bold text-sm inline-block">
              Submit Your First Project
            </Link>
          </div>
        ) : (
          <div className="space-y-4">
            {projects.map(p => (
              <div key={p._id}
                   style={{ background: '#111827', border: '1px solid #1f2937' }}
                   className="rounded-2xl p-6">

                <div className="flex items-start justify-between mb-4">
                  <div>
                    <h3 className="font-bold text-lg">{p.title}</h3>
                    <span style={{ background: '#1f2937', color: '#9ca3af' }}
                          className="text-xs px-2 py-0.5 rounded-full mt-1 inline-block">{p.category}</span>
                  </div>
                  <div className="flex items-center gap-3">
                    <span style={{ color: statusColors[p.status], background: `${statusColors[p.status]}15`, border: `1px solid ${statusColors[p.status]}40` }}
                          className="px-3 py-1 rounded-full text-xs font-medium capitalize">
                      {p.status}
                    </span>

                    {/* Delete button */}
                    {confirmDeleteId === p._id ? (
                      <div className="flex items-center gap-2">
                        <span className="text-xs text-gray-400">Are you sure?</span>
                        <button
                          onClick={() => handleDelete(p._id)}
                          disabled={deletingId === p._id}
                          style={{ background: '#ef4444', color: 'white' }}
                          className="px-3 py-1 rounded-lg text-xs font-semibold hover:opacity-90 disabled:opacity-60 transition-all">
                          {deletingId === p._id ? 'Deleting...' : 'Yes, Delete'}
                        </button>
                        <button
                          onClick={() => setConfirmDeleteId(null)}
                          style={{ background: '#1f2937', color: '#9ca3af' }}
                          className="px-3 py-1 rounded-lg text-xs font-semibold hover:opacity-90 transition-all">
                          Cancel
                        </button>
                      </div>
                    ) : (
                      <button
                        onClick={() => setConfirmDeleteId(p._id)}
                        style={{ border: '1px solid #374151', color: '#ef4444' }}
                        className="px-3 py-1 rounded-lg text-xs font-semibold hover:border-red-500 hover:bg-red-500 hover:bg-opacity-10 transition-all">
                        🗑 Delete
                      </button>
                    )}
                  </div>
                </div>

                {/* Funding progress */}
                <div className="mb-4">
                  <div className="flex justify-between text-sm mb-1.5">
                    <span className="text-gray-400">Funding Progress</span>
                    <span className="font-semibold">${p.currentFunding.toLocaleString()} / ${p.fundingGoal.toLocaleString()}</span>
                  </div>
                  <div style={{ background: '#0a0d1a', height: 8, borderRadius: 4 }}>
                    <div style={{ background: '#00d4aa', width: `${p.fundingPercentage}%`, height: '100%', borderRadius: 4 }} />
                  </div>
                  <span className="text-xs text-gray-500 mt-1 block">{p.fundingPercentage}% funded</span>
                </div>

                {/* AI Evaluation */}
                {p.aiEvaluation?.feasibilityScore !== null ? (
                  <div style={{ background: '#0a0d1a', border: '1px solid #1f2937' }} className="rounded-xl p-4">
                    <p style={{ color: '#00d4aa' }} className="text-xs font-semibold uppercase tracking-wider mb-3">
                      ✦ Gemini AI Evaluation
                    </p>
                    <div className="space-y-2 mb-3">
                      <ScoreBadge label="Feasibility" score={p.aiEvaluation.feasibilityScore} />
                      <ScoreBadge label="Success Prob." score={p.aiEvaluation.successProbability} />
                    </div>
                    {p.aiEvaluation.explanation && (
                      <p className="text-gray-400 text-xs leading-relaxed">{p.aiEvaluation.explanation}</p>
                    )}
                  </div>
                ) : (
                  <div style={{ background: '#0a0d1a', border: '1px solid #1f2937' }}
                       className="rounded-xl p-4 text-center text-gray-500 text-sm">
                    ⏳ AI evaluation in progress...
                  </div>
                )}

                {p.adminNote && (
                  <div style={{ background: 'rgba(245,158,11,0.05)', border: '1px solid rgba(245,158,11,0.2)' }}
                       className="rounded-xl p-3 mt-3">
                    <span className="text-xs text-amber-400">Admin note: </span>
                    <span className="text-xs text-gray-300">{p.adminNote}</span>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
